mapper.select:
SELECT u.id AS unit_id, p.id AS property_id, tw.id AS tower_id, p.property_name, tw.tower_name, p.city AS location, p.property_type, u.unit_code AS unit_number, CASE WHEN LOCATE('-', u.unit_code) > 0 THEN SUBSTRING(u.unit_code, LOCATE('-', u.unit_code) + 1, 2) ELSE '01' END AS floor, u.unit_type, AS area, 'Sq.ft' AS area_unit, 'AVAILABLE' AS availability_status, #{startDate} AS available_from_date, AS monthly_rent, CASE WHEN p.city = 'Doha' THEN 'QAR' ELSE 'AED' END AS currency, ( * 2) AS security_deposit, 450 AS maintenance_charges, 275 AS cam_charges, CASE WHEN u.unit_type = 'RETAIL' THEN 300 ELSE 150 END AS parking_charges, CASE WHEN u.unit_type = 'RETAIL' THEN '12 months' ELSE '6 months' END AS minimum_lease_duration, CASE WHEN u.unit_type = 'RETAIL' THEN '30 days' ELSE '15 days' END AS fit_out_period, '60 days' AS notice_period, '5% annual escalation after first term' AS escalation_terms, CASE WHEN u.unit_type = 'APARTMENT' THEN 'FURNISHED' ELSE 'NON_FURNISHED' END AS furnishing_status, 'Lobby, security, maintenance desk' AS amenities, 'Available' AS parking_availability, '' AS image_url FROM unit_master u INNER JOIN property p ON p.id = u.property_id INNER JOIN tower tw ON tw.id = u.tower_id WHERE u.is_deleted = FALSE AND u.status = 'ACTIVE' AND u.occupancy_status = 'VACANT' AND NOT EXISTS ( SELECT 1 FROM reservation_unit ru INNER JOIN reservation r ON r.id = ru.reservation_id WHERE ru.unit_id = u.id AND ru.is_deleted = FALSE AND r.is_deleted = FALSE AND ru.reservation_status IN ('DRAFT', 'RESERVED') AND r.reservation_status IN ('DRAFT', 'RESERVED') AND r.reservation_date <= #{endDate} AND r.expiry_date >= #{startDate} ) AND NOT EXISTS ( SELECT 1 FROM pm_lease l WHERE l.is_deleted = FALSE AND l.lease_status = 'ACTIVE' AND l.start_date <= #{endDate} AND l.end_date >= #{startDate} AND ( l.unit_id = u.id OR EXISTS ( SELECT 1 FROM pm_lease_unit lu WHERE lu.lease_id = l.id AND lu.unit_id = u.id AND lu.is_deleted = FALSE ) ) ) AND p.id = #{propertyId} AND tw.id = #{towerId} AND p.property_type = #{propertyType} AND u.unit_type = #{unitType}
AND (LOWER(u.unit_code) LIKE CONCAT('%', LOWER(#{unitSearch}), '%') OR LOWER(u.unit_name) LIKE CONCAT('%', LOWER(#{unitSearch}), '%'))
AND LOWER(p.city) LIKE CONCAT('%', LOWER(#{location}), '%') AND >= #{minArea} AND <= #{maxArea} AND >= #{minRent} AND <= #{maxRent} AND (u.unit_type = #{leaseType} OR p.property_type = #{leaseType})
AND CASE WHEN u.unit_type = 'APARTMENT' THEN 'FURNISHED' ELSE 'NON_FURNISHED' END = #{furnishingStatus}
AND CASE WHEN LOCATE('-', u.unit_code) > 0 THEN SUBSTRING(u.unit_code, LOCATE('-', u.unit_code) + 1, 2) ELSE '01' END = #{floor}
AND CASE WHEN u.unit_type = 'OFFICE' THEN 18 WHEN u.unit_type = 'RETAIL' THEN 8 ELSE 4 END >= #{capacity} ORDER BY p.property_name, u.unit_code LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM unit_master u
INNER JOIN property p ON p.id = u.property_id
INNER JOIN tower tw ON tw.id = u.tower_id
WHERE u.is_deleted = FALSE
  AND u.status = 'ACTIVE'
  AND u.occupancy_status = 'VACANT'
  AND NOT EXISTS (
      SELECT 1 FROM reservation_unit ru
      INNER JOIN reservation r ON r.id = ru.reservation_id
      WHERE ru.unit_id = u.id AND ru.is_deleted = FALSE AND r.is_deleted = FALSE
        AND ru.reservation_status IN ('DRAFT', 'RESERVED') AND r.reservation_status IN ('DRAFT', 'RESERVED')
        AND r.reservation_date <= #{endDate} AND r.expiry_date >= #{startDate}
  )
  AND NOT EXISTS (
      SELECT 1 FROM pm_lease l
      WHERE l.is_deleted = FALSE AND l.lease_status = 'ACTIVE'
        AND l.start_date <= #{endDate} AND l.end_date >= #{startDate}
        AND (l.unit_id = u.id OR EXISTS (
            SELECT 1 FROM pm_lease_unit lu
            WHERE lu.lease_id = l.id AND lu.unit_id = u.id AND lu.is_deleted = FALSE
        ))
  )
AND p.id = #{propertyId}
AND tw.id = #{towerId}
AND p.property_type = #{propertyType}
AND u.unit_type = #{unitType}

    AND (LOWER(u.unit_code) LIKE CONCAT('%', LOWER(#{unitSearch}), '%') OR LOWER(u.unit_name) LIKE CONCAT('%', LOWER(#{unitSearch}), '%'))

AND LOWER(p.city) LIKE CONCAT('%', LOWER(#{location}), '%')
AND  >= #{minArea}
AND  <= #{maxArea}
AND  >= #{minRent}
AND  <= #{maxRent}
AND (u.unit_type = #{leaseType} OR p.property_type = #{leaseType})

    AND CASE WHEN u.unit_type = 'APARTMENT' THEN 'FURNISHED' ELSE 'NON_FURNISHED' END = #{furnishingStatus}


    AND CASE WHEN LOCATE('-', u.unit_code) > 0 THEN SUBSTRING(u.unit_code, LOCATE('-', u.unit_code) + 1, 2) ELSE '01' END = #{floor}

AND CASE WHEN u.unit_type = 'OFFICE' THEN 18 WHEN u.unit_type = 'RETAIL' THEN 8 ELSE 4 END >= #{capacity}

SELECT FROM reservation r INNER JOIN property p ON p.id = r.property_id INNER JOIN tower tw ON tw.id = r.tower_id INNER JOIN unit_master u ON u.id = r.unit_id INNER JOIN customer c ON c.id = r.customer_id LEFT JOIN pm_lease l ON l.id = r.converted_lease_id LEFT JOIN ( SELECT reservation_id, COUNT(*) AS total_reserved_units, SUM(area) AS total_reserved_area, SUM(rent) AS total_rent_amount, SUM(deposit) AS total_deposit_amount FROM reservation_unit WHERE is_deleted = FALSE GROUP BY reservation_id ) ru ON ru.reservation_id = r.id WHERE r.is_deleted = FALSE
AND ( LOWER(r.reservation_number) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(p.property_name) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(c.customer_name) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(u.unit_code) LIKE CONCAT('%', LOWER(#{search}), '%') )
AND r.reservation_status = #{reservationStatus}
AND r.workflow_status = #{workflowStatus}
ORDER BY r.id DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM reservation r INNER JOIN property p ON p.id = r.property_id INNER JOIN unit_master u ON u.id = r.unit_id INNER JOIN customer c ON c.id = r.customer_id WHERE r.is_deleted = FALSE
AND ( LOWER(r.reservation_number) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(p.property_name) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(c.customer_name) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(u.unit_code) LIKE CONCAT('%', LOWER(#{search}), '%') )
AND r.reservation_status = #{reservationStatus}
AND r.workflow_status = #{workflowStatus}

mapper.insert:
INSERT INTO reservation_unit (
    tenant_id, reservation_id, property_id, tower_id, unit_id, unit_number, unit_type, area, rent, deposit, tax, reservation_status
)
VALUES (
    1, #{reservationId}, #{unit.propertyId}, #{unit.towerId}, #{unit.unitId}, #{unit.unitNumber}, #{unit.unitType}, #{unit.area}, #{unit.rent}, #{unit.deposit}, #{unit.tax}, #{unit.reservationStatus}
)

INSERT INTO reservation (
    tenant_id, reservation_number, property_id, tower_id, unit_id, customer_id, reservation_status,
    workflow_status, payment_status, reservation_date, expiry_date, proposed_lease_start_date, proposed_lease_end_date,
    quoted_rent, currency, deposit_amount, created_by, lead_name, notes
)
VALUES (
    1, #{reservationNumber}, #{propertyId}, #{towerId}, #{unitId}, #{customerId}, #{reservationStatus},
    #{workflowStatus}, #{paymentStatus}, #{reservationDate}, #{expiryDate}, #{proposedLeaseStartDate}, #{proposedLeaseEndDate},
    #{quotedRent}, #{currency}, #{depositAmount}, #{createdBy}, #{leadName}, #{notes}
)

INSERT INTO reservation_status_history (
    tenant_id, reservation_id, previous_status, new_status, action_type, remarks, created_by
)
VALUES (
    1, #{reservationId}, #{previousStatus}, #{newStatus}, #{actionType}, #{remarks}, #{createdBy}
)

mapper.select:
SELECT COUNT(*)
FROM reservation_unit ru
INNER JOIN reservation r ON r.id = ru.reservation_id
WHERE ru.unit_id = #{unitId}
  AND ru.is_deleted = FALSE
  AND r.is_deleted = FALSE
  AND ru.reservation_status IN ('DRAFT', 'RESERVED')
  AND r.reservation_status IN ('DRAFT', 'RESERVED')
  AND r.id != #{excludeId}
  AND r.reservation_date <= #{expiryDate}
  AND r.expiry_date >= #{reservationDate}

mapper.update:
UPDATE reservation_unit
SET reservation_status = #{status},
    updated_date = CURRENT_TIMESTAMP
WHERE reservation_id = #{reservationId}
  AND unit_id = #{unitId}
  AND is_deleted = FALSE

mapper.select:
SELECT COUNT(*)
FROM pm_lease l
WHERE l.is_deleted = FALSE
  AND l.lease_status = 'ACTIVE'
  AND l.start_date <= #{endDate}
  AND l.end_date >= #{startDate}
  AND (
      l.unit_id = #{unitId}
      OR EXISTS (
          SELECT 1
          FROM pm_lease_unit lu
          WHERE lu.lease_id = l.id
            AND lu.unit_id = #{unitId}
            AND lu.is_deleted = FALSE
      )
  )
